import { useState, useRef, useEffect } from 'react';
import { getIngredients } from '../services/gemini';

const SUGGESTIONS = [
  '🍫 Chocolate Cake',
  '🍝 Pasta Carbonara',
  '🍛 Chicken Biryani',
  '🥞 Pancakes',
  '🍕 Margherita Pizza',
  '🥗 Caesar Salad',
];

function ChatBox({ onIngredientsFound }) {
  const [messages, setMessages] = useState([
    { role: 'bot', text: "Hi! 👋 What would you like to cook today?" }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState('recipe');
  const [data, setData] = useState({
    recipe: '',
    people: '',
    allergies: '',
    preferences: '',
    hasBudget: null,
    budget: ''
  });
  const [showSuggestions, setShowSuggestions] = useState(true);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, loading]);

  const addMsg = (role, text) => setMessages(prev => [...prev, { role, text }]);

  const handleSuggestion = (suggestion) => {
    const text = suggestion.replace(/^.{2}/, '').trim();
    setShowSuggestions(false);
    setInput('');
    addMsg('user', text);
    setData(prev => ({ ...prev, recipe: text }));
    setStep('people');
    setTimeout(() => addMsg('bot', "How many people are you cooking for? 👥"), 400);
  };

  const handleBudgetChoice = (hasbudget) => {
    if (hasbudget) {
      addMsg('user', 'Yes, I have a budget');
      setData(prev => ({ ...prev, hasBudget: true }));
      setStep('budgetAmount');
      setTimeout(() => addMsg('bot', "What is your budget in £? (e.g. 10, 15, 20)"), 400);
    } else {
      addMsg('user', 'No budget limit');
      const finalData = { ...data, hasBudget: false, budget: '' };
      setData(finalData);
      setStep('done');
      fetchIngredients(finalData);
    }
  };

  const fetchIngredients = async (finalData) => {
    setLoading(true);
    addMsg('bot', `Perfect! Finding ingredients for ${finalData.recipe} for ${finalData.people} people... 🛒`);
    try {
      const prompt = `
        Recipe: ${finalData.recipe}
        People: ${finalData.people}
        Allergies to avoid: ${finalData.allergies}
        Dietary preferences: ${finalData.preferences}
        ${finalData.hasBudget ? `Budget: £${finalData.budget} total — pick budget-friendly options and cheaper alternatives where possible` : ''}
      `;
      const result = await getIngredients(prompt);
      addMsg('bot', result.reply);
      onIngredientsFound(result.ingredients);
    } catch (e) {
      addMsg('bot', 'Something went wrong, please try again!');
      setStep('recipe');
    }
    setLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim()) return;
    const text = input.trim();
    setInput('');
    setShowSuggestions(false);
    addMsg('user', text);

    if (step === 'recipe') {
      setData(prev => ({ ...prev, recipe: text }));
      setStep('people');
      setTimeout(() => addMsg('bot', "How many people are you cooking for? 👥"), 400);

    } else if (step === 'people') {
      setData(prev => ({ ...prev, people: text }));
      setStep('allergies');
      setTimeout(() => addMsg('bot', "Any food allergies? 🥜\n(e.g. nuts, gluten, dairy — or type 'none')"), 400);

    } else if (step === 'allergies') {
      setData(prev => ({ ...prev, allergies: text }));
      setStep('preferences');
      setTimeout(() => addMsg('bot', "Any dietary preferences? 🥗\n(e.g. vegan, halal, low sugar — or type 'none')"), 400);

    } else if (step === 'preferences') {
      setData(prev => ({ ...prev, preferences: text }));
      setStep('budget');
      setTimeout(() => addMsg('bot', "Do you have a budget for this shop? 💰"), 500);

    } else if (step === 'budgetAmount') {
      const finalData = { ...data, budget: text };
      setData(finalData);
      setStep('done');
      fetchIngredients(finalData);
    }
  };

  return (
    <div className="chatbox">
      <div
        className="messages"
        style={{ overflowY: 'auto', maxHeight: 340 }}
      >
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`} style={{ whiteSpace: 'pre-line' }}>
            {m.text}
          </div>
        ))}

        {step === 'budget' && !loading && (
          <div className="budget-choice">
            <button
              className="budget-btn"
              onClick={() => handleBudgetChoice(true)}
            >
              💰 Yes, I have a budget
            </button>
            <button
              className="budget-btn budget-btn-no"
              onClick={() => handleBudgetChoice(false)}
            >
              🛒 No limit
            </button>
          </div>
        )}

        {loading && <div className="msg bot">Finding ingredients... 🔍</div>}
        <div ref={bottomRef} />
      </div>

      {showSuggestions && (
        <div className="suggestions">
          <div className="suggestions-label">Popular recipes</div>
          <div className="chips">
            {SUGGESTIONS.map((s, i) => (
              <button key={i} className="chip" onClick={() => handleSuggestion(s)}>
                {s}
              </button>
            ))}
          </div>
        </div>
      )}

      {step !== 'budget' && (
        <div className="input-row">
          <input
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
            placeholder={
              step === 'recipe' ? "e.g. chocolate cake..." :
              step === 'people' ? "e.g. 2, 4, 6..." :
              step === 'allergies' ? "e.g. nuts, gluten or none..." :
              step === 'preferences' ? "e.g. vegan, halal or none..." :
              step === 'budgetAmount' ? "e.g. £10, £15, £20..." :
              "Ask something else..."
            }
          />
          <button onClick={handleSend}>Send</button>
        </div>
      )}
    </div>
  );
}

export default ChatBox;
